-- Ghana Tertiary UniConnect Dataset - part 9
-- Run parts sequentially in Supabase SQL Editor.

insert into public.departments (source_id, university_id, faculty_id, name) select 'ktu_business_and_management_studies_accounting', u.id, f.id, 'Accounting' from public.universities u join public.faculties f on f.source_id = 'ktu_business_and_management_studies' where u.source_id = 'ktu' and not exists (select 1 from public.departments where source_id = 'ktu_business_and_management_studies_accounting' or (university_id = u.id and name = 'Accounting'));
update public.departments set source_id = coalesce(source_id, 'ktu_business_and_management_studies_accounting'), faculty_id = (select id from public.faculties where source_id = 'ktu_business_and_management_studies') where source_id = 'ktu_business_and_management_studies_accounting' or (name = 'Accounting' and university_id = (select id from public.universities where source_id = 'ktu'));
